import React, { Fragment, useState, useEffect } from "react";
import { Col, Card, CardHeader, CardBody, Form, FormGroup, Label, Row } from 'reactstrap';
import { Btn, H3, Breadcrumbs } from "../../../AbstractElements";
import { useForm, Controller } from 'react-hook-form';
import { useNavigate } from 'react-router-dom';
import Select from 'react-select';
import { Save, Cancel } from "../../../Constant";
import { getArea, getAreaRole, getCustomers, getCustomersRole } from "../../../CommonUrl";
import { useSelector } from "react-redux";
import { getClientUrlDataToken, postClientUrlWithToken } from "../../../Utils/restUtils";
import { toast } from 'react-toastify';
import Transparentspinner from "../../Common/Loader/Transparentspinner";

const SendMessage = () => {
    const { register, handleSubmit, control, watch, setValue, formState: { errors } } = useForm({
        defaultValues: {
            serviceType: '',
            recipientType: '',
            selectedAreas: [],
            selectedCustomers: [],
            allCustomers: false,
            reason: '',
            details: ''
        }
    });

    const authState = useSelector((state) => state.auth);
    const [loading, setLoading] = useState(false);
    const [areas, setAreas] = useState([]);
    const [customers, setCustomers] = useState([]);
    const navigate = useNavigate();

    const recipientType = watch('recipientType');
    const allCustomers = watch('allCustomers');
    const reasonValue = watch('reason') || '';
    const detailsValue = watch('details') || '';

    // Clear selected customers if "Send to All Customers" is checked
    useEffect(() => {
        if (allCustomers) {
            setValue('selectedCustomers', []);
        }
    }, [allCustomers, setValue]);

    const handleApiErrorStatus = (status) => {
        if (status >= 400 && status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (status >= 500 && status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
    };

    // Fetch Areas and Customers lists
    useEffect(() => {
        const fetchDropdownData = async () => {
            setLoading(true);
            try {
                const areaRes = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getArea : getAreaRole);
                if (areaRes.status === true) {
                    setAreas(areaRes.data.map(item => ({
                        value: item.id,
                        label: item.name
                    })));
                } else {
                    handleApiErrorStatus(areaRes.status);
                }

                const customerRes = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getCustomers : getCustomersRole);
                if (customerRes.status === true) {
                    setCustomers(customerRes.data.map(item => ({
                        value: item.id,
                        label: item.name
                    })));
                } else {
                    handleApiErrorStatus(customerRes.status);
                }
            } catch (err) {
                console.error("Error fetching lists:", err);
                toast.error("Failed to load area or customer records.");
            } finally {
                setLoading(false);
            }
        };

        fetchDropdownData();
    }, []);

    const onSubmit = async (data) => {
        setLoading(true);
        const postRequest = {
            service_type: data.serviceType,
            recipient_type: data.recipientType,
            areas: data.recipientType === 'Area' ? data.selectedAreas?.map(item => item.value) : [],
            customers: data.recipientType === 'Customer' && !data.allCustomers ? data.selectedCustomers?.map(item => item.value) : [],
            all_customers: data.recipientType === 'Customer' ? data.allCustomers : false,
            reason: data.reason,
            details: data.details
        };

        try {
            const sendUrl = authState.userRole === 1 ? '/admin/send-custom-message' : '/send-custom-message';
            const response = await postClientUrlWithToken(authState.apiUrl, sendUrl, postRequest);
            if (response.status === 200) {
                if (response.data.status === true) {
                    toast.success(response.data.message || "Custom message sent successfully!");
                    navigate(-1);
                } else {
                    toast.error(response.data.message || "Failed to send message.");
                    setLoading(false);
                }
            } else {
                // Graceful fallback for non-implemented backend endpoints in dev environment
                toast.warning(`Custom message submitted (simulation). Backend status: ${response.status}`);
                console.log("Custom message payload:", postRequest);
                navigate(-1);
            }
        } catch (err) {
            console.error("Submission error:", err);
            toast.error("An error occurred during submission.");
            setLoading(false);
        }
    };

    const selectStyles = {
        control: (baseStyles, state) => ({
            ...baseStyles,
            minHeight: 45,
        }),
        menu: (baseStyles) => ({
            ...baseStyles,
            zIndex: 1000,
        }),
    };

    const selectTheme = (theme) => ({
        ...theme,
        colors: {
            ...theme.colors,
            primary25: 'rgba(83, 70, 134, 0.474)',
            primary: '#534686',
            primary50: 'rgba(83, 70, 134, 0.3)'
        },
    });

    const serviceTypeOptions = [
        { value: 'WhatsApp', label: 'WhatsApp' },
        { value: 'SMS', label: 'SMS' }
    ];

    const recipientTypeOptions = [
        { value: 'Area', label: 'Area' },
        { value: 'Customer', label: 'Customer' }
    ];

    return (
        <Fragment>
            {loading && (
                <Transparentspinner />
            )}

            <Breadcrumbs mainTitle="Send Message" parent="Settings" title="Send Message" />
            <Card>
                <CardHeader className="pb-0">
                    <H3>Send Custom Message</H3>
                </CardHeader>
                <CardBody>
                    <Form className="needs-validation" noValidate onSubmit={handleSubmit(onSubmit)}>
                        <Row className="g-3 pt-3">
                            <Col md='6'>
                                <Label className="form-label">Service Type <span className="requireStar">*</span></Label>
                                <Controller
                                    name="serviceType"
                                    control={control}
                                    rules={{ required: 'Service Type is required' }}
                                    render={({ field }) => (
                                        <Select
                                            options={serviceTypeOptions}
                                            value={serviceTypeOptions.find(opt => opt.value === field.value)}
                                            onChange={(selected) => field.onChange(selected ? selected.value : '')}
                                            placeholder="Select Service Type..."
                                            styles={selectStyles}
                                            theme={selectTheme}
                                        />
                                    )}
                                />
                                <span className="text-danger">{errors.serviceType && errors.serviceType.message}</span>
                            </Col>

                            <Col md='6'>
                                <Label className="form-label">Recipient Type <span className="requireStar">*</span></Label>
                                <Controller
                                    name="recipientType"
                                    control={control}
                                    rules={{ required: 'Recipient Type is required' }}
                                    render={({ field }) => (
                                        <Select
                                            options={recipientTypeOptions}
                                            value={recipientTypeOptions.find(opt => opt.value === field.value)}
                                            onChange={(selected) => {
                                                field.onChange(selected ? selected.value : '');
                                                setValue('selectedAreas', []);
                                                setValue('selectedCustomers', []);
                                                setValue('allCustomers', false);
                                            }}
                                            placeholder="Select Recipient Type..."
                                            styles={selectStyles}
                                            theme={selectTheme}
                                        />
                                    )}
                                />
                                <span className="text-danger">{errors.recipientType && errors.recipientType.message}</span>
                            </Col>

                            {recipientType === 'Area' && (
                                <Col md='6'>
                                    <Label className="form-label">Select Areas <span className="requireStar">*</span></Label>
                                    <Controller
                                        name="selectedAreas"
                                        control={control}
                                        rules={{ required: recipientType === 'Area' ? 'Please select at least one area' : false }}
                                        render={({ field }) => (
                                            <Select
                                                isMulti
                                                options={areas}
                                                value={field.value}
                                                onChange={field.onChange}
                                                placeholder="Select Areas..."
                                                styles={selectStyles}
                                                theme={selectTheme}
                                            />
                                        )}
                                    />
                                    <span className="text-danger">{errors.selectedAreas && errors.selectedAreas.message}</span>
                                </Col>
                            )}

                            {recipientType === 'Customer' && (
                                <>
                                    <Col md='6'>
                                        <Label className="form-label">Select Customers <span className="requireStar">*</span></Label>
                                        <Controller
                                            name="selectedCustomers"
                                            control={control}
                                            rules={{ required: (recipientType === 'Customer' && !allCustomers) ? 'Please select at least one customer' : false }}
                                            render={({ field }) => (
                                                <Select
                                                    isMulti
                                                    options={customers}
                                                    value={field.value}
                                                    onChange={field.onChange}
                                                    placeholder={allCustomers ? "All Customers Selected" : "Select Customers..."}
                                                    isDisabled={allCustomers}
                                                    styles={selectStyles}
                                                    theme={selectTheme}
                                                />
                                            )}
                                        />
                                        <span className="text-danger">{errors.selectedCustomers && errors.selectedCustomers.message}</span>
                                    </Col>
                                    <Col md='12'>
                                        <FormGroup check className="mt-2">
                                            <Label check>
                                                <input
                                                    type="checkbox"
                                                    className="form-check-input"
                                                    {...register('allCustomers')}
                                                />{' '}
                                                Send to All Customers
                                            </Label>
                                        </FormGroup>
                                    </Col>
                                </>
                            )}

                            <Col md='6'>
                                <Label className="form-label" for="reason">Reason <span className="requireStar">*</span></Label>
                                <input
                                    className="form-control"
                                    id="reason"
                                    type="text"
                                    placeholder="Enter Reason"
                                    maxLength={100}
                                    {...register('reason', {
                                        required: 'Reason is required',
                                        maxLength: { value: 100, message: 'Reason must be under 100 characters' }
                                    })}
                                />
                                <div className="d-flex justify-content-between mt-1">
                                    <span className="text-danger">{errors.reason && errors.reason.message}</span>
                                    <small className="text-muted">{reasonValue.length}/100</small>
                                </div>
                            </Col>

                            <Col md='12'>
                                <Label className="form-label" for="details">Details <span className="requireStar">*</span></Label>
                                <textarea
                                    className="form-control"
                                    id="details"
                                    rows="4"
                                    placeholder="Enter Message Details"
                                    maxLength={1000}
                                    {...register('details', {
                                        required: 'Details are required',
                                        maxLength: { value: 1000, message: 'Details must be under 1000 characters' }
                                    })}
                                />
                                <div className="d-flex justify-content-between mt-1">
                                    <span className="text-danger">{errors.details && errors.details.message}</span>
                                    <small className="text-muted">{detailsValue.length}/1000</small>
                                </div>
                            </Col>
                        </Row>
                        <FormGroup className="mt-4">
                            <Btn attrBtn={{ color: "primary" }} type="submit">{Save}</Btn>
                            <Btn attrBtn={{ color: "light", className: "ms-2" }} onClick={() => navigate(-1)} type="button">{Cancel}</Btn>
                        </FormGroup>
                    </Form>
                </CardBody>
            </Card>
        </Fragment>
    );
};

export default SendMessage;